#include <stdio.h>
int maxSumIncreasingSubsequence(int arr[], int n) {
    int maxSum = 0;
    int dp[n];
    for (int i = 0; i < n; i++) {
        dp[i] = arr[i];
    }
    for (int i = 1; i < n; i++) {
        for (int j = 0; j < i; j++) {
            if (arr[i] > arr[j]) {
                dp[i] = (dp[i] > dp[j] + arr[i]) ? dp[i] : dp[j] + arr[i];
            }
        }
    }
    for (int i = 0; i < n; i++) {
        maxSum = (maxSum > dp[i]) ? maxSum : dp[i];
    }
    return maxSum;
}
int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n;
        scanf("%d", &n);
        int arr[n];
        for (int i = 0; i < n; i++) {
            scanf("%d", &arr[i]);
        }
        printf("%d\n", maxSumIncreasingSubsequence(arr, n));
    }
    return 0;
}

