#include <iostream>
using namespace std;
int maxSumIncreasingSubsequence(int arr[], int n) {
    int maxSum = 0;
    int dp[n];
    for (int i = 0; i < n; i++) {
        dp[i] = arr[i];
    }
    for (int i = 1; i < n; i++) {
        for (int j = 0; j < i; j++) {
            if (arr[i] > arr[j]) {
                dp[i] = max(dp[i], dp[j] + arr[i]);
            }
        }
    }
    for (int i = 0; i < n; i++) {
        maxSum = max(maxSum, dp[i]);
    }
    return maxSum;
}
